// AUTO-GENERATED DRAFT SCREEN: ErrorLogsAdminScreen
import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import { MoonIcon, SunIcon, SearchIcon, RefreshCcwIcon } from 'lucide-react';

// Mock tRPC hooks for demonstration purposes
// In a real application, these would be generated by tRPC
const trpc = {
  errorLogs: {
    useQuery: (filters: any) => {
      const [data, setData] = useState<any[]>([]);
      const [isLoading, setIsLoading] = useState(true);
      const [isError, setIsError] = useState(false);

      useEffect(() => {
        setIsLoading(true);
        setIsError(false);
        // Simulate API call
        const timer = setTimeout(() => {
          if (Math.random() > 0.9) {
            setIsError(true);
            setData([]);
          } else {
            const mockLogs = Array.from({ length: 10 }, (_, i) => ({
              id: `log-${i + 1}`,
              timestamp: new Date().toISOString(),
              level: ['ERROR', 'WARN', 'INFO'][Math.floor(Math.random() * 3)],
              message: `Error message ${i + 1} related to some service failure.`,
              service: `Service${Math.floor(Math.random() * 3) + 1}`,
            }));
            setData(mockLogs.filter((log) => {
              const levelMatch = !filters.level || log.level === filters.level;
              const searchMatch = !filters.search || log.message.toLowerCase().includes(filters.search.toLowerCase());
              return levelMatch && searchMatch;
            }));
          }
          setIsLoading(false);
        }, 1000);
        return () => clearTimeout(timer);
      }, [filters]);

      return { data, isLoading, isError, refetch: () => {} };
    },
  },
};

interface ErrorLog {
  id: string;
  timestamp: string;
  level: 'ERROR' | 'WARN' | 'INFO';
  message: string;
  service: string;
}

const ErrorLogsAdminScreen: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterLevel, setFilterLevel] = useState<string | undefined>(undefined);
  const [isDarkTheme, setIsDarkTheme] = useState(false);

  const { data: errorLogs, isLoading, isError, refetch } = trpc.errorLogs.useQuery({
    search: searchTerm,
    level: filterLevel,
  });

  useEffect(() => {
    if (isDarkTheme) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkTheme]);

  return (
    <div className={`min-h-screen p-8 ${isDarkTheme ? 'dark bg-gray-900 text-gray-100' : 'bg-gray-50 text-gray-900'}`}>
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold">Error Logs Admin</h1>
        <div className="flex items-center space-x-4">
          <div className="flex items-center space-x-2">
            <SunIcon className="h-5 w-5" />
            <Switch
              checked={isDarkTheme}
              onCheckedChange={setIsDarkTheme}
              aria-label="Toggle dark theme"
            />
            <MoonIcon className="h-5 w-5" />
          </div>
          <Button onClick={refetch} disabled={isLoading} aria-label="Refresh logs">
            <RefreshCcwIcon className={`h-4 w-4 ${isLoading ? 'animate-spin' : ''}`} />
            <span className="ml-2">Refresh</span>
          </Button>
        </div>
      </div>

      <Card className="w-full">
        <CardHeader>
          <CardTitle>Error Log Entries</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex flex-col md:flex-row gap-4 mb-6">
            <div className="relative flex-grow">
              <Input
                type="text"
                placeholder="Search logs..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10"
                aria-label="Search error logs by message"
              />
              <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-500" />
            </div>
            <Select onValueChange={(value) => setFilterLevel(value === 'all' ? undefined : value)} value={filterLevel || 'all'}>
              <SelectTrigger className="w-[180px]">
                <SelectValue placeholder="Filter by Level" aria-label="Filter logs by level" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Levels</SelectItem>
                <SelectItem value="ERROR">ERROR</SelectItem>
                <SelectItem value="WARN">WARN</SelectItem>
                <SelectItem value="INFO">INFO</SelectItem>
              </SelectContent>
            </Select>
          </div>

          {isLoading && (
            <div className="flex justify-center items-center h-48">
              <RefreshCcwIcon className="h-8 w-8 animate-spin text-blue-500" />
              <span className="ml-3 text-lg">Loading logs...</span>
            </div>
          )}

          {isError && (
            <div className="flex justify-center items-center h-48 text-red-500">
              <p className="text-lg">Failed to load error logs. Please try again.</p>
            </div>
          )}

          {!isLoading && !isError && errorLogs && errorLogs.length === 0 && (
            <div className="flex justify-center items-center h-48 text-gray-500">
              <p className="text-lg">No error logs found matching your criteria.</p>
            </div>
          )}

          {!isLoading && !isError && errorLogs && errorLogs.length > 0 && (
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead className="w-[100px]">ID</TableHead>
                    <TableHead>Timestamp</TableHead>
                    <TableHead>Level</TableHead>
                    <TableHead>Message</TableHead>
                    <TableHead>Service</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {errorLogs.map((log: ErrorLog) => (
                    <TableRow key={log.id}>
                      <TableCell className="font-medium">{log.id}</TableCell>
                      <TableCell>{new Date(log.timestamp).toLocaleString()}</TableCell>
                      <TableCell>
                        <span className={`px-2 py-1 rounded-full text-xs font-semibold
                          ${log.level === 'ERROR' ? 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200' :
                            log.level === 'WARN' ? 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200' :
                            'bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200'}
                        `}>
                          {log.level}
                        </span>
                      </TableCell>
                      <TableCell>{log.message}</TableCell>
                      <TableCell>{log.service}</TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

export default ErrorLogsAdminScreen;
